using CopilotTest.Models;

namespace CopilotTest.Services;

/// <summary>
/// Offline monster service — full SRD 5e monster list, no network required.
/// </summary>
public class DndApiService
{
    public bool ApiAvailable => false;
    public string ApiStatusMessage => $"Built-in SRD monsters ({BuiltInMonsters.Count})";

    public Task<List<MonsterSummary>> GetMonsterListAsync()
    {
        var list = BuiltInMonsters
            .Select(m => new MonsterSummary { Index = m.Index, Name = m.Name })
            .ToList();
        return Task.FromResult(list);
    }

    public Task<MonsterDetail?> GetMonsterDetailAsync(string index)
    {
        var result = BuiltInMonsters
            .FirstOrDefault(m => m.Index.Equals(index, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult<MonsterDetail?>(result);
    }

    public Task<List<MonsterSummary>> SearchMonstersAsync(string query)
    {
        var all = BuiltInMonsters
            .Select(m => new MonsterSummary { Index = m.Index, Name = m.Name });
        if (string.IsNullOrWhiteSpace(query))
            return Task.FromResult(all.ToList());
        return Task.FromResult(
            all.Where(m => m.Name.Contains(query, StringComparison.OrdinalIgnoreCase)).ToList());
    }

    private static readonly Random _rng = new();

    public MonsterSummary GetRandomMonsterSummary()
    {
        var idx = _rng.Next(BuiltInMonsters.Count);
        var m = BuiltInMonsters[idx];
        return new MonsterSummary { Index = m.Index, Name = m.Name };
    }

    public Combatant MonsterToCombatant(MonsterDetail monster)
    {
        var combatant = new Combatant
        {
            Name             = monster.Name,
            Type             = CombatantType.Monster,
            Strength         = monster.Strength,
            Dexterity        = monster.Dexterity,
            Constitution     = monster.Constitution,
            Intelligence     = monster.Intelligence,
            Wisdom           = monster.Wisdom,
            Charisma         = monster.Charisma,
            MaxHitPoints     = monster.Hit_Points,
            CurrentHitPoints = monster.Hit_Points,
            ArmorClass       = monster.GetArmorClass(),
            ProficiencyBonus = monster.Proficiency_Bonus
        };

        var attackActions = monster.Actions
            .Where(a => a.Attack_Bonus.HasValue && a.Damage.Count > 0)
            .ToList();

        if (attackActions.Count > 0)
        {
            foreach (var ma in attackActions)
            {
                combatant.Actions.Add(new CombatAction
                {
                    Name         = ma.Name,
                    ActionType   = ActionType.Attack,
                    AttackBonus  = ma.Attack_Bonus ?? Combatant.GetModifier(monster.Strength),
                    DamageDice   = ma.Damage.FirstOrDefault()?.Damage_Dice?.Value ?? "1d6",
                    DamageBonus  = Combatant.GetModifier(monster.Strength),
                    Range        = "5 ft",
                    Description  = ma.Desc
                });
            }
        }
        else
        {
            combatant.Actions.Add(new CombatAction
            {
                Name        = "Attack",
                ActionType  = ActionType.Attack,
                AttackBonus = Combatant.GetModifier(monster.Strength) + monster.Proficiency_Bonus,
                DamageDice  = "1d6",
                DamageBonus = Combatant.GetModifier(monster.Strength)
            });
        }

        return combatant;
    }

